import React, { useState, useEffect, useCallback } from 'react';
import { ChevronDown, ChevronUp, Loader2, WifiOff, CalendarDays } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from '@/components/ui/collapsible';
import { Header } from '@/components/Header';
import { MenuDrawer } from '@/components/MenuDrawer';
import { FiltersDrawer } from '@/components/FiltersDrawer';
import { InspectionCard } from '@/components/InspectionCard';
import { useAuth } from '@/context/AuthContext';
import { inspectionsApi } from '@/lib/api';
import { format, isToday, isYesterday, isTomorrow } from 'date-fns';
import { toast } from 'sonner';

export default function DashboardPage() {
  const { mechanic } = useAuth();
  const [menuOpen, setMenuOpen] = useState(false);
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [activeExpanded, setActiveExpanded] = useState(true);
  const [completedExpanded, setCompletedExpanded] = useState(false);
  const [rejectedExpanded, setRejectedExpanded] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [inspections, setInspections] = useState([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [filters, setFilters] = useState({
    date: new Date(),
    city: mechanic?.city || '',
    status: '',
    myCityOnly: true
  });

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const fetchInspections = useCallback(async () => {
    setIsLoading(true);
    try {
      const params = {};
      if (filters.date) {
        params.date = format(new Date(filters.date), 'yyyy-MM-dd');
      }
      if (filters.city || filters.myCityOnly) {
        params.city = filters.myCityOnly ? mechanic?.city : filters.city;
      }
      if (filters.status) {
        params.status = filters.status;
      }
      const data = await inspectionsApi.getInspections(params);
      setInspections(Array.isArray(data) ? data : []);
      localStorage.setItem('cachedInspections', JSON.stringify(data));
    } catch (err) {
      console.error('Failed to fetch inspections:', err);
      const cached = localStorage.getItem('cachedInspections');
      if (cached) {
        setInspections(JSON.parse(cached));
        toast.info('Showing cached data');
      } else {
        toast.error('Failed to load inspections');
      }
    } finally {
      setIsLoading(false);
    }
  }, [filters, mechanic?.city]);

  useEffect(() => {
    fetchInspections();
  }, [fetchInspections]);

  const handleAccept = async (id) => {
    try {
      await inspectionsApi.acceptInspection(id);
      toast.success('Inspection accepted');
      fetchInspections();
    } catch (err) {
      toast.error('Failed to accept inspection');
    }
  };

  const handleReject = async (id, reason) => {
    try {
      await inspectionsApi.rejectInspection(id, reason);
      toast.success('Inspection rejected');
      fetchInspections();
    } catch (err) {
      toast.error('Failed to reject inspection');
    }
  };

  // Format the selected date for display
  const getDateDisplayText = () => {
    const date = filters.date ? new Date(filters.date) : new Date();
    if (isToday(date)) return 'Today';
    if (isYesterday(date)) return 'Yesterday';
    if (isTomorrow(date)) return 'Tomorrow';
    return format(date, 'MMM dd, yyyy');
  };

  // Categorize inspections
  const activeInspections = inspections.filter(i => i.status === 'NEW' || i.status === 'ACCEPTED');
  const completedInspections = inspections.filter(i => i.status === 'COMPLETED');
  const rejectedInspections = inspections.filter(i => i.status === 'REJECTED');

  const hasActiveFilters = filters.status || (!filters.myCityOnly && filters.city);

  return (
    <div className="min-h-screen bg-slate-50">
      <Header 
        onMenuClick={() => setMenuOpen(true)}
        logo="https://customer-assets.emergentagent.com/job_mechanic-assist-10/artifacts/wxp3v8bu_Wisedrive%20New%20Logo%20Horizontal%20Black%20Trans%20BG.png"
        showFilters={true}
        selectedDate={filters.date}
        onDateChange={(date) => setFilters({ ...filters, date })}
        onFilterClick={() => setFiltersOpen(true)}
        hasActiveFilters={hasActiveFilters}
      />
      
      <MenuDrawer open={menuOpen} onClose={setMenuOpen} />
      <FiltersDrawer 
        open={filtersOpen} 
        onClose={setFiltersOpen}
        filters={filters}
        onFiltersChange={setFilters}
        mechanicCity={mechanic?.city}
      />

      <main className="pt-20 pb-8 px-4">
        {/* Offline Banner */}
        {!isOnline && (
          <div 
            data-testid="offline-banner"
            className="bg-amber-50 border border-amber-200 rounded-xl p-3 mb-4 flex items-center gap-2 text-amber-700"
          >
            <WifiOff className="w-4 h-4" />
            <span className="text-sm font-medium">You&apos;re offline</span>
          </div>
        )}

        {/* Date Display Banner */}
        <div 
          data-testid="date-display-banner"
          className="bg-blue-50 border border-blue-100 rounded-xl p-3 mb-4 flex items-center gap-3"
        >
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center">
            <CalendarDays className="w-5 h-5 text-white" />
          </div>
          <div>
            <div className="text-xs text-blue-600 font-medium uppercase tracking-wide">Viewing inspections for</div>
            <div className="text-lg font-bold text-slate-900">{getDateDisplayText()}</div>
          </div>
          <div className="ml-auto text-xs text-slate-500">
            {format(filters.date ? new Date(filters.date) : new Date(), 'EEEE')}
          </div>
        </div>

        {/* Section Header */}
        <div className="flex items-center justify-between mb-4">
          <div>
            <h2 
              data-testid="section-title"
              className="text-xl font-bold text-slate-900"
              style={{ fontFamily: 'Barlow Condensed, sans-serif' }}
            >
              Inspections
            </h2>
            <p className="text-sm text-slate-500">{mechanic?.city}</p>
          </div>
        </div>

        {/* Clear Filters */}
        {hasActiveFilters && (
          <button
            data-testid="clear-filters-link"
            onClick={() => setFilters({ date: new Date(), city: mechanic?.city || '', status: '', myCityOnly: true })}
            className="text-blue-600 text-sm font-medium mb-4 block"
          >
            Clear Filters
          </button>
        )}

        {/* Loading State */}
        {isLoading ? (
          <div className="flex items-center justify-center py-16">
            <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
          </div>
        ) : (
          <div className="space-y-3">
            {/* Active Inspections Section */}
            <Collapsible open={activeExpanded} onOpenChange={setActiveExpanded}>
              <CollapsibleTrigger asChild>
                <Button
                  data-testid="active-section-toggle"
                  variant="ghost"
                  className="w-full flex items-center justify-between px-4 py-3 bg-white rounded-xl border border-slate-100"
                >
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-blue-500" />
                    <span className="font-semibold text-slate-800">
                      Active ({activeInspections.length})
                    </span>
                  </div>
                  {activeExpanded ? (
                    <ChevronUp className="w-5 h-5 text-slate-400" />
                  ) : (
                    <ChevronDown className="w-5 h-5 text-slate-400" />
                  )}
                </Button>
              </CollapsibleTrigger>
              <CollapsibleContent className="mt-3 space-y-3">
                {activeInspections.length === 0 ? (
                  <div 
                    data-testid="no-active-inspections"
                    className="text-center py-8 text-slate-400 text-sm"
                  >
                    No active inspections
                  </div>
                ) : (
                  activeInspections.map((inspection) => (
                    <InspectionCard
                      key={inspection.id}
                      inspection={inspection}
                      onAccept={handleAccept}
                      onReject={handleReject}
                    />
                  ))
                )}
              </CollapsibleContent>
            </Collapsible>

            {/* Completed Inspections Section */}
            <Collapsible open={completedExpanded} onOpenChange={setCompletedExpanded}>
              <CollapsibleTrigger asChild>
                <Button
                  data-testid="completed-section-toggle"
                  variant="ghost"
                  className="w-full flex items-center justify-between px-4 py-3 bg-white rounded-xl border border-slate-100"
                >
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-emerald-500" />
                    <span className="font-semibold text-slate-800">
                      Completed ({completedInspections.length})
                    </span>
                  </div>
                  {completedExpanded ? (
                    <ChevronUp className="w-5 h-5 text-slate-400" />
                  ) : (
                    <ChevronDown className="w-5 h-5 text-slate-400" />
                  )}
                </Button>
              </CollapsibleTrigger>
              <CollapsibleContent className="mt-3 space-y-3">
                {completedInspections.length === 0 ? (
                  <div 
                    data-testid="no-completed-inspections"
                    className="text-center py-8 text-slate-400 text-sm"
                  >
                    No completed inspections
                  </div>
                ) : (
                  completedInspections.map((inspection) => (
                    <InspectionCard
                      key={inspection.id}
                      inspection={inspection}
                    />
                  ))
                )}
              </CollapsibleContent>
            </Collapsible>

            {/* Rejected Inspections Section */}
            <Collapsible open={rejectedExpanded} onOpenChange={setRejectedExpanded}>
              <CollapsibleTrigger asChild>
                <Button
                  data-testid="rejected-section-toggle"
                  variant="ghost"
                  className="w-full flex items-center justify-between px-4 py-3 bg-white rounded-xl border border-slate-100"
                >
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-red-400" />
                    <span className="font-semibold text-slate-800">
                      Rejected ({rejectedInspections.length})
                    </span>
                  </div>
                  {rejectedExpanded ? (
                    <ChevronUp className="w-5 h-5 text-slate-400" />
                  ) : (
                    <ChevronDown className="w-5 h-5 text-slate-400" />
                  )}
                </Button>
              </CollapsibleTrigger>
              <CollapsibleContent className="mt-3 space-y-3">
                {rejectedInspections.length === 0 ? (
                  <div 
                    data-testid="no-rejected-inspections"
                    className="text-center py-8 text-slate-400 text-sm"
                  >
                    No rejected inspections
                  </div>
                ) : (
                  rejectedInspections.map((inspection) => (
                    <InspectionCard
                      key={inspection.id}
                      inspection={inspection}
                    />
                  ))
                )}
              </CollapsibleContent>
            </Collapsible>
          </div>
        )}
      </main>
    </div>
  );
}
