import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Header } from '@/components/Header';
import { inspectionsApi } from '@/lib/api';
import { toast } from 'sonner';

export default function StartInspectionPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [inspection, setInspection] = useState(null);
  const [vehicleNumber, setVehicleNumber] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isVerifying, setIsVerifying] = useState(false);

  useEffect(() => {
    const fetchInspection = async () => {
      setIsLoading(true);
      try {
        const data = await inspectionsApi.getInspection(id);
        setInspection(data);
      } catch (err) {
        toast.error('Failed to load inspection');
        navigate('/');
      } finally {
        setIsLoading(false);
      }
    };
    fetchInspection();
  }, [id, navigate]);

  const handleConfirm = async () => {
    const cleanInput = vehicleNumber.replace(/\s/g, '').toUpperCase();
    const expectedNumber = inspection?.vehicleNumber?.replace(/\s/g, '').toUpperCase();
    
    if (cleanInput !== expectedNumber) {
      toast.error('Vehicle number does not match. Please check and try again.');
      return;
    }

    setIsVerifying(true);
    try {
      // Fetch vehicle details and navigate to confirmation
      navigate(`/vehicle-details/${id}`);
    } catch (err) {
      toast.error('Failed to verify vehicle');
    } finally {
      setIsVerifying(false);
    }
  };

  const handleInputChange = (e) => {
    // Auto uppercase and format
    const value = e.target.value.toUpperCase();
    setVehicleNumber(value);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      <Header title="Start Inspection" showBack />

      <main className="pt-20 px-6 flex flex-col items-center justify-center min-h-[calc(100vh-80px)]">
        <div className="w-full max-w-sm text-center">
          <h1 className="text-2xl font-bold text-slate-900 mb-2">
            Enter Car Registration No.
          </h1>
          <p className="text-slate-500 mb-8">
            Enter the vehicle number plate you see in front of you
          </p>

          <Input
            data-testid="vehicle-number-input"
            type="text"
            value={vehicleNumber}
            onChange={handleInputChange}
            placeholder="KA03NC2764"
            className="h-14 text-center text-xl font-bold tracking-widest uppercase border-2 border-blue-500 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 vehicle-input"
            maxLength={15}
          />

          <Button
            data-testid="confirm-vehicle-btn"
            onClick={handleConfirm}
            disabled={vehicleNumber.length < 6 || isVerifying}
            className="w-full h-14 mt-6 bg-blue-600 hover:bg-blue-700 text-white font-bold text-base rounded-xl uppercase tracking-wide"
          >
            {isVerifying ? (
              <Loader2 className="w-5 h-5 animate-spin" />
            ) : (
              'Confirm'
            )}
          </Button>
        </div>
      </main>
    </div>
  );
}
