/**
 * Push Notification Service for Mechanic App
 * 
 * This service handles Firebase Cloud Messaging (FCM) for push notifications.
 * 
 * For a web app, we use the Web Push API with Firebase.
 * For a React Native app, this would use react-native-firebase.
 * 
 * Setup steps for production:
 * 1. Create Firebase project at https://console.firebase.google.com
 * 2. Add web app to Firebase project
 * 3. Copy firebaseConfig values to this file
 * 4. Enable Cloud Messaging in Firebase console
 * 5. Generate VAPID key for web push
 */

import { pushNotificationApi } from './api';

// Firebase configuration (replace with your actual config in production)
const firebaseConfig = {
  apiKey: process.env.REACT_APP_FIREBASE_API_KEY || "",
  authDomain: process.env.REACT_APP_FIREBASE_AUTH_DOMAIN || "",
  projectId: process.env.REACT_APP_FIREBASE_PROJECT_ID || "",
  storageBucket: process.env.REACT_APP_FIREBASE_STORAGE_BUCKET || "",
  messagingSenderId: process.env.REACT_APP_FIREBASE_MESSAGING_SENDER_ID || "",
  appId: process.env.REACT_APP_FIREBASE_APP_ID || "",
};

// VAPID key for web push (get from Firebase Console > Project Settings > Cloud Messaging)
const VAPID_KEY = process.env.REACT_APP_FIREBASE_VAPID_KEY || "";

let firebaseApp = null;
let messaging = null;

/**
 * Initialize Firebase for push notifications
 */
export const initializeFirebase = async () => {
  // Check if Firebase config is available
  if (!firebaseConfig.apiKey || !firebaseConfig.projectId) {
    console.log('Firebase config not available - push notifications disabled');
    return false;
  }

  try {
    // Dynamically import Firebase (tree-shaking friendly)
    const { initializeApp } = await import('firebase/app');
    const { getMessaging, getToken, onMessage } = await import('firebase/messaging');

    // Initialize Firebase app
    firebaseApp = initializeApp(firebaseConfig);
    messaging = getMessaging(firebaseApp);

    console.log('Firebase initialized for push notifications');
    return true;
  } catch (error) {
    console.error('Failed to initialize Firebase:', error);
    return false;
  }
};

/**
 * Request notification permission and get FCM token
 */
export const requestNotificationPermission = async () => {
  // Check if browser supports notifications
  if (!('Notification' in window)) {
    console.log('This browser does not support notifications');
    return null;
  }

  // Check if service worker is supported
  if (!('serviceWorker' in navigator)) {
    console.log('Service workers not supported');
    return null;
  }

  try {
    // Request permission
    const permission = await Notification.requestPermission();
    
    if (permission !== 'granted') {
      console.log('Notification permission denied');
      return null;
    }

    // Get FCM token
    if (!messaging) {
      const initialized = await initializeFirebase();
      if (!initialized) return null;
    }

    const { getToken } = await import('firebase/messaging');
    
    const token = await getToken(messaging, {
      vapidKey: VAPID_KEY
    });

    if (token) {
      console.log('FCM Token obtained');
      // Register token with backend
      await registerTokenWithBackend(token);
      return token;
    }

    return null;
  } catch (error) {
    console.error('Error getting notification permission:', error);
    return null;
  }
};

/**
 * Register FCM token with backend
 */
export const registerTokenWithBackend = async (token) => {
  try {
    const platform = /iPhone|iPad|iPod/.test(navigator.userAgent) ? 'ios' : 'android';
    const deviceInfo = {
      userAgent: navigator.userAgent,
      platform: navigator.platform,
      language: navigator.language
    };

    await pushNotificationApi.registerToken(token, platform, deviceInfo);
    
    // Store token locally for reference
    localStorage.setItem('fcmToken', token);
    
    console.log('Push token registered with backend');
    return true;
  } catch (error) {
    console.error('Failed to register push token:', error);
    return false;
  }
};

/**
 * Unregister push token (call on logout)
 */
export const unregisterPushToken = async () => {
  try {
    await pushNotificationApi.unregisterToken();
    localStorage.removeItem('fcmToken');
    console.log('Push token unregistered');
    return true;
  } catch (error) {
    console.error('Failed to unregister push token:', error);
    return false;
  }
};

/**
 * Setup foreground message handler
 */
export const setupMessageHandler = (callback) => {
  if (!messaging) {
    console.log('Firebase messaging not initialized');
    return;
  }

  import('firebase/messaging').then(({ onMessage }) => {
    onMessage(messaging, (payload) => {
      console.log('Received foreground message:', payload);
      
      // Show notification manually for foreground messages
      if (Notification.permission === 'granted') {
        const { title, body } = payload.notification || {};
        const notificationOptions = {
          body,
          icon: '/logo192.png',
          badge: '/logo192.png',
          data: payload.data
        };

        new Notification(title || 'New Notification', notificationOptions);
      }

      // Call the callback with payload
      if (callback) {
        callback(payload);
      }
    });
  });
};

/**
 * Check if push notifications are enabled
 */
export const isPushEnabled = () => {
  return (
    'Notification' in window &&
    Notification.permission === 'granted' &&
    localStorage.getItem('fcmToken') !== null
  );
};

/**
 * Get current FCM token
 */
export const getCurrentToken = () => {
  return localStorage.getItem('fcmToken');
};

export default {
  initializeFirebase,
  requestNotificationPermission,
  registerTokenWithBackend,
  unregisterPushToken,
  setupMessageHandler,
  isPushEnabled,
  getCurrentToken
};
