import React from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { Toaster } from "@/components/ui/sonner";
import { AuthProvider, useAuth } from "@/context/AuthContext";

// Pages
import LoginPage from "@/pages/LoginPage";
import DashboardPage from "@/pages/DashboardPage";
import StartInspectionPage from "@/pages/StartInspectionPage";
import VehicleDetailsPage from "@/pages/VehicleDetailsPage";
import InspectionChecklistPage from "@/pages/InspectionChecklistPage";
import CategoryDetailPage from "@/pages/CategoryDetailPage";
import EarningsPage from "@/pages/EarningsPage";
import SupportPage from "@/pages/SupportPage";

// Protected Route Component
const ProtectedRoute = ({ children }) => {
  const { isAuthenticated, isLoading } = useAuth();
  
  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }
  
  if (!isAuthenticated) {
    return <Navigate to="/login" replace />;
  }
  
  return children;
};

// Public Route (redirect to dashboard if logged in)
const PublicRoute = ({ children }) => {
  const { isAuthenticated, isLoading } = useAuth();
  
  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }
  
  if (isAuthenticated) {
    return <Navigate to="/" replace />;
  }
  
  return children;
};

function AppRoutes() {
  return (
    <Routes>
      {/* Public Routes */}
      <Route 
        path="/login" 
        element={
          <PublicRoute>
            <LoginPage />
          </PublicRoute>
        } 
      />
      
      {/* Protected Routes */}
      <Route 
        path="/" 
        element={
          <ProtectedRoute>
            <DashboardPage />
          </ProtectedRoute>
        } 
      />
      <Route 
        path="/start-inspection/:id" 
        element={
          <ProtectedRoute>
            <StartInspectionPage />
          </ProtectedRoute>
        } 
      />
      <Route 
        path="/vehicle-details/:id" 
        element={
          <ProtectedRoute>
            <VehicleDetailsPage />
          </ProtectedRoute>
        } 
      />
      <Route 
        path="/inspection-checklist/:id" 
        element={
          <ProtectedRoute>
            <InspectionChecklistPage />
          </ProtectedRoute>
        } 
      />
      <Route 
        path="/category/:inspectionId/:categoryId" 
        element={
          <ProtectedRoute>
            <CategoryDetailPage />
          </ProtectedRoute>
        } 
      />
      <Route 
        path="/earnings" 
        element={
          <ProtectedRoute>
            <EarningsPage />
          </ProtectedRoute>
        } 
      />
      <Route 
        path="/support" 
        element={
          <ProtectedRoute>
            <SupportPage />
          </ProtectedRoute>
        } 
      />
      
      {/* Fallback */}
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
}

function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <div className="App max-w-md mx-auto min-h-screen bg-slate-50 shadow-2xl relative">
          <AppRoutes />
          <Toaster position="top-center" richColors />
        </div>
      </BrowserRouter>
    </AuthProvider>
  );
}

export default App;
