// Auth API
export const authApi = {
  requestOtp: async (phone) => {
    if (MOCK_MODE) {
      const mechanic = mockMechanics.find(m => m.phone === phone && m.active);
      if (!mechanic) {
        throw { response: { status: 404, data: { message: 'You are not onboarded yet. Please contact Wisedrive support.' } } };
      }
      return { success: true, message: 'OTP sent successfully' };
    }
    const response = await api.post('/auth/request-otp', { phone });
    return response.data;
  },

  verifyOtp: async (phone, otp) => {
    if (MOCK_MODE) {
      const mechanic = mockMechanics.find(m => m.phone === phone && m.active);
      if (!mechanic) {
        throw { response: { status: 404, data: { message: 'Mechanic not found' } } };
      }
      if (otp !== '123456') {
        throw { response: { status: 400, data: { message: 'Invalid OTP' } } };
      }
      return { token: 'mock-jwt-token', mechanicProfile: mechanic };
    }
    const response = await api.post('/auth/verify-otp', { phone, otp });
    return response.data;
  },
};

// Inspections API - Uses /mechanic/ prefixed endpoints for mechanic app
export const inspectionsApi = {
  getInspections: async (params = {}) => {
    if (MOCK_MODE) {
      let filtered = [...mockInspections];
      if (params.status) {
        filtered = filtered.filter(i => i.status === params.status);
      }
      if (params.city) {
        filtered = filtered.filter(i => i.city === params.city);
      }
      if (params.date) {
        const targetDate = new Date(params.date).toDateString();
        filtered = filtered.filter(i => new Date(i.scheduledAt).toDateString() === targetDate);
      }
      return filtered;
    }
    const response = await api.get('/mechanic/inspections', { params });
    return response.data;
  },

  getInspection: async (id) => {
    if (MOCK_MODE) {
      const inspection = mockInspections.find(i => i.id === id);
      if (!inspection) {
        throw { response: { status: 404, data: { message: 'Inspection not found' } } };
      }
      return inspection;
    }
    const response = await api.get(`/mechanic/inspections/${id}`);
    return response.data;
  },

  acceptInspection: async (id) => {
    if (MOCK_MODE) {
      const index = mockInspections.findIndex(i => i.id === id);
      if (index !== -1) {
        mockInspections[index].status = 'ACCEPTED';
        mockInspections[index].assignedMechanicId = 'M001';
      }
      return mockInspections[index];
    }
    const response = await api.post(`/mechanic/inspections/${id}/accept`);
    return response.data;
  },

  rejectInspection: async (id, reason) => {
    if (MOCK_MODE) {
      const index = mockInspections.findIndex(i => i.id === id);
      if (index !== -1) {
        mockInspections[index].status = 'REJECTED';
        mockInspections[index].rejectionReason = reason;
      }
      return mockInspections[index];
    }
    const response = await api.post(`/mechanic/inspections/${id}/reject`, { reason });
    return response.data;
  },

  saveProgress: async (id, progress) => {
    if (MOCK_MODE) {
      const index = mockInspections.findIndex(i => i.id === id);
      if (index !== -1) {
        mockInspections[index].progress = { ...mockInspections[index].progress, ...progress };
      }
      return mockInspections[index];
    }
    const response = await api.post(`/mechanic/inspections/${id}/progress`, { progress_data: progress });
    return response.data;
  },

  completeInspection: async (id) => {
    if (MOCK_MODE) {
      const index = mockInspections.findIndex(i => i.id === id);
      if (index !== -1) {
        mockInspections[index].status = 'COMPLETED';
      }
      return mockInspections[index];
    }
    const response = await api.post(`/mechanic/inspections/${id}/complete`);
    return response.data;
  },
  
  // Get questionnaire for an inspection (client-specific questions)
  getQuestionnaire: async (id) => {
    if (MOCK_MODE) {
      // Return mock categories for mock mode
      return {
        inspection_id: id,
        questions: [],
        total_questions: 0
      };
    }
    const response = await api.get(`/inspections/${id}/questionnaire`);
    return response.data;
  },
};

// Upload API
export const uploadApi = {
  uploadFile: async (file, type) => {
    if (MOCK_MODE) {
      return { url: URL.createObjectURL(file), type };
    }
    const formData = new FormData();
    formData.append('file', file);
    formData.append('type', type);
    const response = await api.post('/uploads', formData, {
      headers: { 'Content-Type': 'multipart/form-data' },
    });
    return response.data;
  },
};

// Push Notification API
export const pushNotificationApi = {
  // Register FCM push token
  registerToken: async (deviceToken, platform = 'android', deviceInfo = null) => {
    if (MOCK_MODE) {
      console.log('[MOCK] Push token registered:', deviceToken);
      return { success: true, message: 'Push token registered (mock)' };
    }
    const response = await api.post('/mechanic/push-token', {
      device_token: deviceToken,
      platform,
      device_info: deviceInfo
    });
    return response.data;
  },

  // Unregister push token (on logout)
  unregisterToken: async () => {
    if (MOCK_MODE) {
      console.log('[MOCK] Push token unregistered');
      return { success: true };
    }
    const response = await api.delete('/mechanic/push-token');
    return response.data;
  },

  // Get notification history
  getNotifications: async (limit = 50) => {
    if (MOCK_MODE) {
      return [];
    }
    const response = await api.get('/mechanic/notifications', { params: { limit } });
    return response.data;
  },

  // Mark notification as read
  markAsRead: async (notificationId) => {
    if (MOCK_MODE) {
      return { success: true };
    }
    const response = await api.patch(`/mechanic/notifications/${notificationId}/read`);
    return response.data;
  }
};

export default api;
