import React, { createContext, useContext, useState, useEffect } from 'react';
import { requestNotificationPermission, unregisterPushToken, setupMessageHandler } from '../lib/pushNotification';
import { toast } from 'sonner';

const AuthContext = createContext(null);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [token, setToken] = useState(() => localStorage.getItem('authToken'));
  const [mechanic, setMechanic] = useState(() => {
    const stored = localStorage.getItem('mechanicProfile');
    return stored ? JSON.parse(stored) : null;
  });
  const [isLoading, setIsLoading] = useState(false);
  const [notifications, setNotifications] = useState([]);

  // Setup push notifications when authenticated
  useEffect(() => {
    if (token && mechanic) {
      // Request notification permission and register token
      requestNotificationPermission().then((fcmToken) => {
        if (fcmToken) {
          console.log('Push notifications enabled');
        }
      });

      // Setup foreground message handler
      setupMessageHandler((payload) => {
        // Handle incoming notification while app is open
        const notification = {
          id: payload.data?.notification_id || Date.now().toString(),
          title: payload.notification?.title || 'New Notification',
          body: payload.notification?.body || '',
          data: payload.data,
          createdAt: new Date().toISOString(),
          read: false
        };
        
        setNotifications(prev => [notification, ...prev].slice(0, 50));
        
        // Show toast for new inspection notifications
        if (payload.data?.type === 'new_inspection') {
          toast.info(notification.title, {
            description: notification.body,
            action: {
              label: 'View',
              onClick: () => window.location.href = '/'
            }
          });
        } else if (payload.data?.type === 'inspection_assigned') {
          toast.success(notification.title, {
            description: notification.body
          });
        }
      });
    }
  }, [token, mechanic]);

  const login = async (authToken, mechanicProfile) => {
    localStorage.setItem('authToken', authToken);
    localStorage.setItem('mechanicProfile', JSON.stringify(mechanicProfile));
    setToken(authToken);
    setMechanic(mechanicProfile);
    
    // Register for push notifications after login
    setTimeout(() => {
      requestNotificationPermission();
    }, 1000);
  };

  const logout = async () => {
    // Unregister push token before logging out
    try {
      await unregisterPushToken();
    } catch (e) {
      console.log('Failed to unregister push token:', e);
    }
    
    localStorage.removeItem('authToken');
    localStorage.removeItem('mechanicProfile');
    setToken(null);
    setMechanic(null);
    setNotifications([]);
  };

  const isAuthenticated = !!token && !!mechanic;

  const markNotificationRead = (notificationId) => {
    setNotifications(prev => 
      prev.map(n => n.id === notificationId ? { ...n, read: true } : n)
    );
  };

  const unreadCount = notifications.filter(n => !n.read).length;

  return (
    <AuthContext.Provider value={{ 
      token, 
      mechanic, 
      isAuthenticated, 
      isLoading, 
      login, 
      logout,
      notifications,
      unreadCount,
      markNotificationRead
    }}>
      {children}
    </AuthContext.Provider>
  );
};
