import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetDescription } from '@/components/ui/sheet';
import { Button } from '@/components/ui/button';
import { useAuth } from '@/context/AuthContext';
import { Home, DollarSign, HelpCircle, LogOut, User, MapPin, ChevronRight } from 'lucide-react';

export const MenuDrawer = ({ open, onClose }) => {
  const navigate = useNavigate();
  const { mechanic, logout } = useAuth();

  const handleNavigate = (path) => {
    onClose(false);
    navigate(path);
  };

  const handleLogout = () => {
    logout();
    onClose(false);
    navigate('/login');
  };

  const menuItems = [
    { icon: Home, label: 'Home', path: '/', testId: 'menu-home' },
    { icon: DollarSign, label: 'My Earnings', path: '/earnings', testId: 'menu-earnings' },
    { icon: HelpCircle, label: 'Help & Support', path: '/support', testId: 'menu-support' },
  ];

  return (
    <Sheet open={open} onOpenChange={onClose}>
      <SheetContent side="left" className="w-[85%] max-w-sm p-0 border-0">
        <SheetHeader className="sr-only">
          <SheetTitle>Navigation Menu</SheetTitle>
          <SheetDescription>Access app features and settings</SheetDescription>
        </SheetHeader>
        
        {/* Profile Section */}
        <div className="bg-slate-900 text-white p-6 pt-12">
          <div className="mb-6">
            <img 
              src="https://customer-assets.emergentagent.com/job_mechanic-assist-10/artifacts/wxp3v8bu_Wisedrive%20New%20Logo%20Horizontal%20Black%20Trans%20BG.png"
              alt="Wisedrive"
              className="h-8 brightness-0 invert"
            />
          </div>
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 rounded-full bg-white/10 flex items-center justify-center">
              <User className="w-7 h-7" />
            </div>
            <div>
              <div data-testid="menu-mechanic-name" className="font-bold text-lg">
                {mechanic?.name || 'Mechanic'}
              </div>
              <div className="flex items-center gap-1 text-slate-300 text-sm mt-0.5">
                <MapPin className="w-3.5 h-3.5" />
                <span data-testid="menu-mechanic-city">{mechanic?.city || 'City'}</span>
              </div>
              <div data-testid="menu-mechanic-id" className="text-slate-400 text-xs mt-1">
                ID: {mechanic?.id || 'N/A'}
              </div>
            </div>
          </div>
        </div>

        {/* Menu Items */}
        <div className="py-2">
          {menuItems.map((item) => (
            <Button
              key={item.path}
              data-testid={item.testId}
              variant="ghost"
              onClick={() => handleNavigate(item.path)}
              className="w-full h-14 justify-between px-6 rounded-none text-slate-700 hover:bg-slate-50"
            >
              <div className="flex items-center gap-4">
                <item.icon className="w-5 h-5 text-slate-400" />
                <span className="font-medium">{item.label}</span>
              </div>
              <ChevronRight className="w-5 h-5 text-slate-300" />
            </Button>
          ))}
        </div>

        {/* Logout Button */}
        <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-slate-100">
          <Button
            data-testid="menu-logout"
            variant="ghost"
            onClick={handleLogout}
            className="w-full h-12 justify-start gap-4 text-red-500 hover:text-red-600 hover:bg-red-50"
          >
            <LogOut className="w-5 h-5" />
            <span className="font-medium">Logout</span>
          </Button>
        </div>
      </SheetContent>
    </Sheet>
  );
};
