import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Phone, Loader2, ArrowRight } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { InputOTP, InputOTPGroup, InputOTPSlot } from '@/components/ui/input-otp';
import { useAuth } from '@/context/AuthContext';
import { authApi } from '@/lib/api';
import { toast } from 'sonner';

export default function LoginPage() {
  const navigate = useNavigate();
  const { login } = useAuth();
  const [step, setStep] = useState('phone');
  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const handlePhoneSubmit = async (e) => {
    e.preventDefault();
    setError('');
    
    const cleanPhone = phone.replace(/\D/g, '');
    if (cleanPhone.length < 10) {
      setError('Please enter a valid 10-digit phone number');
      return;
    }

    setIsLoading(true);
    try {
      await authApi.requestOtp(cleanPhone);
      setStep('otp');
      toast.success('OTP sent successfully');
    } catch (err) {
      const message = err.response?.data?.message || 'Failed to send OTP. Please try again.';
      setError(message);
      toast.error(message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleOtpSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (otp.length !== 6) {
      setError('Please enter a valid 6-digit OTP');
      return;
    }

    setIsLoading(true);
    try {
      const cleanPhone = phone.replace(/\D/g, '');
      const response = await authApi.verifyOtp(cleanPhone, otp);
      login(response.token, response.mechanicProfile);
      toast.success('Login successful');
      navigate('/');
    } catch (err) {
      const message = err.response?.data?.message || 'Invalid OTP. Please try again.';
      setError(message);
      toast.error(message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleOtpChange = (value) => {
    setOtp(value);
    setError('');
  };

  const handleResendOtp = async () => {
    setIsLoading(true);
    try {
      const cleanPhone = phone.replace(/\D/g, '');
      await authApi.requestOtp(cleanPhone);
      toast.success('OTP resent successfully');
    } catch (err) {
      toast.error('Failed to resend OTP');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-white flex flex-col">
      {/* Logo Header */}
      <div className="pt-12 pb-6 px-6">
        <img
          src="https://customer-assets.emergentagent.com/job_mechanic-assist-10/artifacts/wxp3v8bu_Wisedrive%20New%20Logo%20Horizontal%20Black%20Trans%20BG.png"
          alt="Wisedrive"
          className="h-9 object-contain"
        />
      </div>

      {/* Main Content */}
      <div className="flex-1 px-6 pb-8">
        {step === 'phone' ? (
          <form onSubmit={handlePhoneSubmit} className="space-y-6">
            <div>
              <h1 className="text-2xl font-bold text-slate-900 mb-2">
                Welcome back
              </h1>
              <p className="text-slate-500 text-sm">
                Enter your registered mobile number to continue
              </p>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-600">
                Mobile Number
              </label>
              <div className="relative">
                <div className="absolute left-0 top-0 bottom-0 w-16 flex items-center justify-center bg-slate-50 border-r border-slate-200 rounded-l-xl">
                  <span className="text-slate-600 font-medium text-sm">+91</span>
                </div>
                <Input
                  data-testid="phone-input"
                  type="tel"
                  value={phone}
                  onChange={(e) => {
                    setPhone(e.target.value);
                    setError('');
                  }}
                  placeholder="Enter 10 digit number"
                  className="h-12 pl-20 text-base border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  maxLength={10}
                  inputMode="numeric"
                />
              </div>
              {error && (
                <p data-testid="login-error" className="text-red-500 text-sm">
                  {error}
                </p>
              )}
            </div>

            <Button
              data-testid="send-otp-btn"
              type="submit"
              disabled={isLoading || phone.length < 10}
              className="w-full h-12 bg-slate-900 hover:bg-slate-800 text-white font-semibold text-sm rounded-xl flex items-center justify-center gap-2"
            >
              {isLoading ? (
                <Loader2 className="w-5 h-5 animate-spin" />
              ) : (
                <>
                  Continue
                  <ArrowRight className="w-4 h-4" />
                </>
              )}
            </Button>

            <p className="text-center text-xs text-slate-400 mt-6">
              Only registered mechanics can access this app
            </p>
          </form>
        ) : (
          <form onSubmit={handleOtpSubmit} className="space-y-6">
            <div>
              <h1 className="text-2xl font-bold text-slate-900 mb-2">
                Verify OTP
              </h1>
              <p className="text-slate-500 text-sm">
                Enter the 6-digit code sent to{' '}
                <span className="font-medium text-slate-700">+91 {phone}</span>
              </p>
            </div>

            <div className="space-y-4">
              <div className="flex justify-center">
                <InputOTP
                  data-testid="otp-input"
                  value={otp}
                  onChange={handleOtpChange}
                  maxLength={6}
                >
                  <InputOTPGroup className="gap-2">
                    {[0, 1, 2, 3, 4, 5].map((index) => (
                      <InputOTPSlot
                        key={index}
                        index={index}
                        className="h-12 w-10 text-lg font-bold rounded-lg border-2 border-slate-200 focus:border-slate-900 focus:ring-0"
                      />
                    ))}
                  </InputOTPGroup>
                </InputOTP>
              </div>
              {error && (
                <p data-testid="otp-error" className="text-red-500 text-sm text-center">
                  {error}
                </p>
              )}
            </div>

            <Button
              data-testid="verify-otp-btn"
              type="submit"
              disabled={isLoading || otp.length !== 6}
              className="w-full h-12 bg-slate-900 hover:bg-slate-800 text-white font-semibold text-sm rounded-xl"
            >
              {isLoading ? (
                <Loader2 className="w-5 h-5 animate-spin" />
              ) : (
                'Verify & Login'
              )}
            </Button>

            <div className="flex items-center justify-between text-sm">
              <button
                data-testid="change-phone-btn"
                type="button"
                onClick={() => {
                  setStep('phone');
                  setOtp('');
                  setError('');
                }}
                className="text-slate-500 hover:text-slate-700 font-medium"
              >
                Change Number
              </button>
              <button
                data-testid="resend-otp-btn"
                type="button"
                onClick={handleResendOtp}
                disabled={isLoading}
                className="text-blue-600 hover:text-blue-700 font-medium"
              >
                Resend OTP
              </button>
            </div>
          </form>
        )}
      </div>

      {/* Bottom Section */}
      <div className="h-32 flex items-end justify-center pb-8">
        <div className="flex items-center gap-2 text-slate-300">
          <Phone className="w-4 h-4" />
          <span className="text-xs">Secure login with OTP</span>
        </div>
      </div>
    </div>
  );
}
