import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ChevronLeft, ChevronRight, Check, Camera, Video, X, Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { uploadApi, inspectionsApi } from '@/lib/api';
import { toast } from 'sonner';

const CATS = {
  engine: { name: 'Engine Health', color: 'bg-orange-500' },
  transmission: { name: 'Transmission', color: 'bg-blue-500' },
  battery: { name: 'Battery Health', color: 'bg-green-500' },
  suspension: { name: 'Suspension & Brakes', color: 'bg-purple-500' },
  tires: { name: 'Tires & Tools', color: 'bg-red-500' },
  general: { name: 'General', color: 'bg-slate-500' }
};

export default function CategoryDetailPage() {
  const { inspectionId, categoryId } = useParams();
  const navigate = useNavigate();
  const [idx, setIdx] = useState(0);
  const [ans, setAns] = useState({});
  const [qs, setQs] = useState([]);
  const [loading, setLoading] = useState(true);

  const cat = CATS[categoryId] || { name: categoryId || 'Category', color: 'bg-slate-500' };

  useEffect(() => {
    const loadQuestions = async () => {
      setLoading(true);
      
      // First try to get questions from localStorage (set by InspectionChecklistPage)
      const storedQuestions = localStorage.getItem(`questions_${inspectionId}_${categoryId}`);
      
      if (storedQuestions) {
        try {
          const questions = JSON.parse(storedQuestions);
          // Transform CRM questions to mechanic app format
          const transformedQuestions = transformQuestions(questions);
          setQs(transformedQuestions);
          setLoading(false);
          return;
        } catch (e) {
          console.error('Failed to parse stored questions:', e);
        }
      }
      
      // Fallback: fetch from backend or static file
      try {
        const questionnaireData = await inspectionsApi.getQuestionnaire(inspectionId);
        const categoryQuestions = questionnaireData.questions?.filter(q => q.category_id === categoryId) || [];
        const transformedQuestions = transformQuestions(categoryQuestions);
        setQs(transformedQuestions);
      } catch (err) {
        // Final fallback to static JSON
        try {
          const response = await fetch('/questions.json');
          const data = await response.json();
          setQs(data[categoryId] || []);
        } catch (e) {
          console.error('Failed to load questions:', e);
          setQs([]);
        }
      }
      
      setLoading(false);
    };
    
    loadQuestions();
  }, [categoryId, inspectionId]);

  // Transform CRM question format to mechanic app format
  const transformQuestions = (crmQuestions) => {
    return crmQuestions.map(q => {
      // Map CRM question type to app type
      let type = 'yes_no';
      let opts = null;
      let sub = null;
      let subs = null;
      
      if (q.type === 'choice' || q.type === 'select') {
        type = 'choice';
        opts = q.options || ['Good', 'Fair', 'Poor'];
      } else if (q.type === 'photo' || q.type === 'image') {
        type = 'photo';
        if (q.followup_question) {
          sub = { q: q.followup_question, opts: q.followup_options || ['Good', 'Fair', 'Poor'] };
        }
      } else if (q.type === 'video') {
        type = 'video';
      } else if (q.type === 'conditional' || q.type === 'yes_no_conditional') {
        type = 'cond_1';
        if (q.followup_question) {
          sub = { q: q.followup_question, opts: q.followup_options || ['Yes', 'No'] };
        }
      }
      
      return {
        id: q.id,
        q: q.question || q.text || q.q,
        type,
        opts,
        sub,
        subs,
        dur: q.duration
      };
    });
  };

  const q = qs[idx];
  const a = q ? (ans[q.id] || {}) : {};

  const setMain = (v) => q && setAns(p => ({ ...p, [q.id]: { ...p[q.id], m: v }}));
  const setSub = (v, i) => q && setAns(p => ({ ...p, [q.id]: { ...p[q.id], [`s${i}`]: v }}));
  const setMedia = (t, u) => q && setAns(p => ({ ...p, [q.id]: { ...p[q.id], [t]: u }}));

  const capture = async (e, t) => {
    const f = e.target.files?.[0];
    if (f) {
      try {
        const r = await uploadApi.uploadFile(f, t);
        setMedia(t, r.url);
        toast.success(t === 'photo' ? 'Photo captured' : 'Video recorded');
      } catch { toast.error('Failed'); }
    }
  };

  const isDone = () => {
    if (!q) return false;
    if (q.type === 'yes_no' || q.type === 'choice') return !!a.m;
    if (q.type === 'cond_1') return a.m === 'No' || (a.m === 'Yes' && a.s0);
    if (q.type === 'cond_2') return a.m === 'No' || (a.m === 'Yes' && a.s0 && a.s1);
    if (q.type === 'photo') return a.photo && (!q.sub || a.s0);
    if (q.type === 'video') return !!a.video;
    if (q.type === 'video_q') return a.video && q.subs?.every((_, i) => a[`s${i}`]);
    return false;
  };

  const saveAnswer = async () => {
    if (q && ans[q.id]) {
      try {
        await inspectionsApi.saveProgress(inspectionId, {
          question_id: q.id,
          answer: ans[q.id]
        });
      } catch (e) {
        console.log('Could not save progress:', e);
      }
    }
  };

  const next = async () => {
    await saveAnswer();
    if (idx < qs.length - 1) setIdx(idx + 1);
    else { 
      toast.success('Category completed!'); 
      // Clear stored questions
      localStorage.removeItem(`questions_${inspectionId}_${categoryId}`);
      navigate(`/inspection-checklist/${inspectionId}`); 
    }
  };

  if (loading) return <div className="min-h-screen bg-slate-50 flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-blue-600" /></div>;
  if (!q) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
        <p className="text-slate-600 mb-4">No questions found for this category</p>
        <Button onClick={() => navigate(`/inspection-checklist/${inspectionId}`)}>
          Go Back
        </Button>
      </div>
    );
  }

  const prog = ((idx + 1) / qs.length) * 100;

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className={`fixed top-0 left-0 right-0 ${cat.color} text-white z-50`}>
        <div className="h-14 flex items-center justify-between px-4">
          <button onClick={() => navigate(`/inspection-checklist/${inspectionId}`)} className="w-10 h-10 flex items-center justify-center"><ChevronLeft className="w-6 h-6" /></button>
          <span className="font-semibold">{cat.name}</span>
          <div className="w-10" />
        </div>
        <div className="h-1 bg-white/20"><div className="h-full bg-white" style={{ width: `${prog}%` }} /></div>
      </header>

      <main className="pt-20 px-4">
        <div className="flex justify-between mb-4">
          <span className="text-sm text-slate-500">Q {idx + 1}/{qs.length}</span>
          <span className="text-xs text-red-500 bg-red-50 px-2 py-1 rounded-full">Required</span>
        </div>

        <div className="bg-white rounded-2xl p-5 shadow-sm">
          <div className="text-base font-medium text-slate-800 mb-4">{q.q}</div>

          {q.type === 'yes_no' && <YesNo value={a.m} onChange={setMain} />}
          {q.type === 'choice' && <Choice opts={q.opts} value={a.m} onChange={setMain} />}
          {q.type === 'cond_1' && <Cond1 q={q} a={a} setMain={setMain} setSub={setSub} />}
          {q.type === 'cond_2' && <Cond2 q={q} a={a} setMain={setMain} setSub={setSub} />}
          {q.type === 'photo' && <PhotoQ q={q} a={a} capture={capture} setMedia={setMedia} setSub={setSub} />}
          {q.type === 'video' && <VideoQ q={q} a={a} capture={capture} setMedia={setMedia} />}
          {q.type === 'video_q' && <VideoQSub q={q} a={a} capture={capture} setMedia={setMedia} setSub={setSub} />}
        </div>
      </main>

      <div className="fixed bottom-0 left-0 right-0 bg-white border-t p-4">
        <div className="flex gap-3">
          <Button onClick={() => idx > 0 && setIdx(idx - 1)} disabled={idx === 0} variant="outline" className="h-12 px-6 rounded-xl"><ChevronLeft className="w-5 h-5" /></Button>
          <Button onClick={next} disabled={!isDone()} className="flex-1 h-12 bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 text-white font-semibold rounded-xl">
            {idx === qs.length - 1 ? <><Check className="w-5 h-5 mr-2" />Done</> : <>Next<ChevronRight className="w-5 h-5 ml-2" /></>}
          </Button>
        </div>
      </div>
    </div>
  );
}

function YesNo({ value, onChange }) {
  return (
    <div className="flex gap-3">
      <button onClick={() => onChange('Yes')} className={`flex-1 h-12 rounded-xl font-semibold ${value === 'Yes' ? 'bg-emerald-500 text-white' : 'bg-slate-100 text-slate-600'}`}>Yes</button>
      <button onClick={() => onChange('No')} className={`flex-1 h-12 rounded-xl font-semibold ${value === 'No' ? 'bg-red-500 text-white' : 'bg-slate-100 text-slate-600'}`}>No</button>
    </div>
  );
}

function Choice({ opts, value, onChange }) {
  return (
    <div className="grid grid-cols-2 gap-2">
      {opts?.map(o => <button key={o} onClick={() => onChange(o)} className={`p-3 rounded-xl text-sm font-medium text-left ${value === o ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-700'}`}>{o}</button>)}
    </div>
  );
}

function SubQ({ label, opts, value, onChange }) {
  return (
    <div className="mt-4 p-4 bg-blue-50 rounded-xl">
      <div className="text-sm font-medium text-blue-800 mb-2">{label}</div>
      <div className="flex flex-wrap gap-2">
        {opts?.map(o => <button key={o} onClick={() => onChange(o)} className={`px-3 py-2 rounded-lg text-sm font-medium ${value === o ? 'bg-blue-600 text-white' : 'bg-white text-slate-700 border'}`}>{o}</button>)}
      </div>
    </div>
  );
}

function Cond1({ q, a, setMain, setSub }) {
  return (
    <>
      <YesNo value={a.m} onChange={setMain} />
      {a.m === 'Yes' && q.sub && <SubQ label={q.sub.q} opts={q.sub.opts} value={a.s0} onChange={v => setSub(v, 0)} />}
    </>
  );
}

function Cond2({ q, a, setMain, setSub }) {
  return (
    <>
      <YesNo value={a.m} onChange={setMain} />
      {a.m === 'Yes' && q.subs?.map((s, i) => <SubQ key={i} label={s.q} opts={s.opts} value={a[`s${i}`]} onChange={v => setSub(v, i)} />)}
    </>
  );
}

function PhotoQ({ q, a, capture, setMedia, setSub }) {
  return (
    <>
      {a.photo ? (
        <div className="relative aspect-[4/3] rounded-xl overflow-hidden bg-slate-100">
          <img src={a.photo} alt="" className="w-full h-full object-cover" />
          <button onClick={() => setMedia('photo', null)} className="absolute top-2 right-2 w-8 h-8 rounded-full bg-red-500 text-white flex items-center justify-center"><X className="w-5 h-5" /></button>
        </div>
      ) : (
        <label className="block cursor-pointer">
          <input type="file" accept="image/*" capture="environment" onChange={e => capture(e, 'photo')} className="hidden" />
          <div className="aspect-[4/3] rounded-xl border-2 border-dashed border-blue-300 bg-blue-50 flex flex-col items-center justify-center">
            <Camera className="w-10 h-10 text-blue-400 mb-2" /><span className="text-sm text-blue-600">Tap to capture</span>
          </div>
        </label>
      )}
      {a.photo && q.sub && <SubQ label={q.sub.q} opts={q.sub.opts} value={a.s0} onChange={v => setSub(v, 0)} />}
    </>
  );
}

function VideoQ({ q, a, capture, setMedia }) {
  return a.video ? (
    <div className="relative aspect-video rounded-xl overflow-hidden bg-slate-900">
      <video src={a.video} controls className="w-full h-full" />
      <button onClick={() => setMedia('video', null)} className="absolute top-2 right-2 w-8 h-8 rounded-full bg-red-500 text-white flex items-center justify-center"><X className="w-5 h-5" /></button>
    </div>
  ) : (
    <label className="block cursor-pointer">
      <input type="file" accept="video/*" capture="environment" onChange={e => capture(e, 'video')} className="hidden" />
      <div className="aspect-video rounded-xl border-2 border-dashed border-purple-300 bg-purple-50 flex flex-col items-center justify-center">
        <Video className="w-10 h-10 text-purple-400 mb-2" /><span className="text-sm text-purple-600">Tap to record</span>
        {q.dur && <span className="text-xs text-purple-500">({q.dur}s)</span>}
      </div>
    </label>
  );
}

function VideoQSub({ q, a, capture, setMedia, setSub }) {
  return (
    <>
      <VideoQ q={q} a={a} capture={capture} setMedia={setMedia} />
      {a.video && q.subs?.map((s, i) => <SubQ key={i} label={s.q} opts={s.opts} value={a[`s${i}`]} onChange={v => setSub(v, i)} />)}
    </>
  );
}
