import React from 'react';
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetDescription } from '@/components/ui/sheet';
import { Button } from '@/components/ui/button';
import { Switch } from '@/components/ui/switch';
import { Calendar } from '@/components/ui/calendar';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { CalendarIcon, X } from 'lucide-react';
import { format } from 'date-fns';
import { cn } from '@/lib/utils';

const cities = ['Bangalore', 'Hyderabad', 'Chennai', 'Mumbai', 'Delhi', 'Pune'];
const statuses = [
  { value: 'all', label: 'All Statuses' },
  { value: 'NEW', label: 'New' },
  { value: 'ACCEPTED', label: 'Accepted' },
  { value: 'COMPLETED', label: 'Completed' },
];

export const FiltersDrawer = ({ 
  open, 
  onClose, 
  filters, 
  onFiltersChange,
  mechanicCity 
}) => {
  const handleDateSelect = (date) => {
    onFiltersChange({ ...filters, date: date || null });
  };

  const handleCityChange = (value) => {
    onFiltersChange({ ...filters, city: value === 'all' ? '' : value });
  };

  const handleStatusChange = (value) => {
    onFiltersChange({ ...filters, status: value === 'all' ? '' : value });
  };

  const handleMyCityToggle = (checked) => {
    onFiltersChange({ 
      ...filters, 
      myCityOnly: checked,
      city: checked ? mechanicCity : ''
    });
  };

  const handleClear = () => {
    onFiltersChange({
      date: new Date(),
      city: '',
      status: '',
      myCityOnly: false
    });
  };

  const hasActiveFilters = filters.city || filters.status || filters.myCityOnly || 
    (filters.date && new Date(filters.date).toDateString() !== new Date().toDateString());

  return (
    <Sheet open={open} onOpenChange={onClose}>
      <SheetContent side="bottom" className="h-[80vh] rounded-t-2xl z-[100]">
        <SheetHeader className="pb-4 border-b">
          <div className="flex items-center justify-between">
            <SheetTitle className="text-lg font-bold">Filters</SheetTitle>
            {hasActiveFilters && (
              <Button
                data-testid="clear-filters-btn"
                variant="ghost"
                onClick={handleClear}
                className="text-blue-600 font-medium h-10"
              >
                Clear All
              </Button>
            )}
          </div>
          <SheetDescription className="sr-only">
            Filter inspections by date, city, and status
          </SheetDescription>
        </SheetHeader>

        <div className="space-y-6 pt-6">
          {/* Date Filter */}
          <div>
            <label className="text-sm font-medium text-slate-700 mb-2 block">Date</label>
            <Popover>
              <PopoverTrigger asChild>
                <Button
                  data-testid="date-filter-btn"
                  variant="outline"
                  className={cn(
                    "w-full h-12 justify-start text-left font-normal border-slate-300",
                    !filters.date && "text-muted-foreground"
                  )}
                >
                  <CalendarIcon className="mr-2 h-4 w-4" />
                  {filters.date ? format(new Date(filters.date), "PPP") : "Select date"}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0" align="start">
                <Calendar
                  mode="single"
                  selected={filters.date ? new Date(filters.date) : undefined}
                  onSelect={handleDateSelect}
                  initialFocus
                />
              </PopoverContent>
            </Popover>
          </div>

          {/* My City Toggle */}
          <div className="flex items-center justify-between py-2">
            <label className="text-sm font-medium text-slate-700">My City Only</label>
            <Switch
              data-testid="my-city-toggle"
              checked={filters.myCityOnly}
              onCheckedChange={handleMyCityToggle}
              className="data-[state=checked]:bg-blue-600"
            />
          </div>

          {/* City Filter */}
          <div>
            <label className="text-sm font-medium text-slate-700 mb-2 block">City</label>
            <Select 
              value={filters.city || 'all'} 
              onValueChange={handleCityChange}
              disabled={filters.myCityOnly}
            >
              <SelectTrigger 
                data-testid="city-filter"
                className="h-12 border-slate-300"
              >
                <SelectValue placeholder="All Cities" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Cities</SelectItem>
                {cities.map(city => (
                  <SelectItem key={city} value={city}>{city}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Status Filter */}
          <div>
            <label className="text-sm font-medium text-slate-700 mb-2 block">Status</label>
            <Select 
              value={filters.status || 'all'} 
              onValueChange={handleStatusChange}
            >
              <SelectTrigger 
                data-testid="status-filter"
                className="h-12 border-slate-300"
              >
                <SelectValue placeholder="All Statuses" />
              </SelectTrigger>
              <SelectContent>
                {statuses.map(s => (
                  <SelectItem key={s.value} value={s.value}>{s.label}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Apply Button */}
          <Button
            data-testid="apply-filters-btn"
            onClick={() => onClose(false)}
            className="w-full h-12 bg-blue-600 hover:bg-blue-700 text-white font-bold text-lg rounded-lg mt-6"
          >
            Apply Filters
          </Button>
        </div>
      </SheetContent>
    </Sheet>
  );
};
