import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Loader2, Camera, X, ChevronRight } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Header } from '@/components/Header';
import { inspectionsApi, uploadApi } from '@/lib/api';
import { toast } from 'sonner';

export default function VehicleDetailsPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [inspection, setInspection] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [vehicleData, setVehicleData] = useState({
    fuelType: 'Petrol',
    transmission: 'Manual',
    kmDriven: '',
    numOwners: '1',
    carPhoto: null,
    odometerPhoto: null
  });

  useEffect(() => {
    const fetchInspection = async () => {
      setIsLoading(true);
      try {
        const data = await inspectionsApi.getInspection(id);
        setInspection(data);
        // Pre-fill with existing data if available
        if (data.vehicleDetails) {
          setVehicleData(prev => ({ ...prev, ...data.vehicleDetails }));
        }
      } catch (err) {
        toast.error('Failed to load vehicle data');
        navigate('/');
      } finally {
        setIsLoading(false);
      }
    };
    fetchInspection();
  }, [id, navigate]);

  const handlePhotoCapture = async (e, photoType) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const result = await uploadApi.uploadFile(file, photoType);
      setVehicleData(prev => ({
        ...prev,
        [photoType]: result.url
      }));
      toast.success('Photo uploaded');
    } catch (err) {
      toast.error('Failed to upload photo');
    }
  };

  const removePhoto = (photoType) => {
    setVehicleData(prev => ({
      ...prev,
      [photoType]: null
    }));
  };

  const handleProceed = async () => {
    try {
      // Save vehicle details
      await inspectionsApi.saveProgress(id, {
        vehicleDetails: vehicleData,
        vehicleVerified: true
      });
      navigate(`/inspection-checklist/${id}`);
    } catch (err) {
      toast.error('Failed to save vehicle details');
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
      </div>
    );
  }

  // Mock vehicle data (would come from API in real app)
  const vehicleInfo = {
    regNumber: inspection?.vehicleNumber || 'KA03NC2764',
    year: '2017',
    make: 'HYUNDAI MOTOR INDIA LTD',
    model: inspection?.makeModelVariant || 'I20 SPORTZ VTVT',
    color: 'MARINA BLUE'
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <Header title="Vehicle Details" showBack />

      <main className="pt-20 px-4">
        {/* Vehicle Info Card */}
        <div className="bg-white rounded-2xl p-4 shadow-sm border border-slate-100 mb-4">
          {/* Reg Number + Year */}
          <div className="flex items-start justify-between mb-4">
            <div>
              <div className="text-xs text-slate-500 font-medium mb-1">Reg. Number</div>
              <div className="text-xl font-bold text-slate-900 tracking-wide">
                {vehicleInfo.regNumber}
              </div>
            </div>
            <div className="text-right">
              <div className="text-xs text-slate-500 font-medium mb-1">Year</div>
              <div className="text-xl font-bold text-slate-900">{vehicleInfo.year}</div>
            </div>
          </div>

          {/* Make */}
          <div className="mb-3">
            <div className="text-xs text-slate-500 font-medium mb-1">Make</div>
            <div className="text-base font-semibold text-slate-800">{vehicleInfo.make}</div>
          </div>

          {/* Model */}
          <div className="mb-4">
            <div className="text-xs text-slate-500 font-medium mb-1">Model</div>
            <div className="text-base font-semibold text-slate-800">{vehicleInfo.model}</div>
          </div>

          <div className="border-t border-slate-100 pt-4">
            {/* Fuel Type */}
            <div className="mb-4">
              <div className="text-xs text-slate-500 font-medium mb-2">Fuel Type</div>
              <div className="flex gap-2">
                {['Petrol', 'Diesel', 'CNG'].map((type) => (
                  <button
                    key={type}
                    data-testid={`fuel-${type.toLowerCase()}`}
                    onClick={() => setVehicleData(prev => ({ ...prev, fuelType: type }))}
                    className={`flex-1 h-10 rounded-lg font-medium text-sm transition-colors ${
                      vehicleData.fuelType === type
                        ? 'bg-blue-600 text-white'
                        : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                    }`}
                  >
                    {type}
                  </button>
                ))}
              </div>
            </div>

            {/* Color */}
            <div className="mb-4">
              <div className="text-xs text-slate-500 font-medium mb-1">Color</div>
              <div className="text-base font-semibold text-slate-800">{vehicleInfo.color}</div>
            </div>

            {/* Transmission */}
            <div className="mb-4">
              <div className="text-xs text-slate-500 font-medium mb-2">Transmission Type</div>
              <div className="flex gap-2">
                {['Automatic', 'Manual'].map((type) => (
                  <button
                    key={type}
                    data-testid={`transmission-${type.toLowerCase()}`}
                    onClick={() => setVehicleData(prev => ({ ...prev, transmission: type }))}
                    className={`flex-1 h-10 rounded-lg font-medium text-sm transition-colors ${
                      vehicleData.transmission === type
                        ? 'bg-blue-600 text-white'
                        : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                    }`}
                  >
                    {type}
                  </button>
                ))}
              </div>
            </div>

            {/* Km Driven + No. of Owners */}
            <div className="flex gap-4 mb-4">
              <div className="flex-1">
                <div className="text-xs text-slate-500 font-medium mb-2">Km Driven</div>
                <Input
                  data-testid="km-driven-input"
                  type="number"
                  value={vehicleData.kmDriven}
                  onChange={(e) => setVehicleData(prev => ({ ...prev, kmDriven: e.target.value }))}
                  placeholder="Enter KM"
                  className="h-10 text-sm"
                />
              </div>
              <div className="flex-1">
                <div className="text-xs text-slate-500 font-medium mb-2">No. Of Owners</div>
                <Input
                  data-testid="num-owners-input"
                  type="number"
                  value={vehicleData.numOwners}
                  onChange={(e) => setVehicleData(prev => ({ ...prev, numOwners: e.target.value }))}
                  placeholder="1"
                  className="h-10 text-sm"
                />
              </div>
            </div>
          </div>
        </div>

        {/* Photo Captures */}
        <div className="grid grid-cols-2 gap-4">
          {/* Car Photo with Reg No */}
          <div>
            <div className="text-xs text-slate-500 font-medium mb-2">Car Photo With Reg No.</div>
            {vehicleData.carPhoto ? (
              <div className="relative aspect-[4/3] rounded-xl overflow-hidden bg-slate-100">
                <img 
                  src={vehicleData.carPhoto} 
                  alt="Car" 
                  className="w-full h-full object-cover"
                />
                <button
                  onClick={() => removePhoto('carPhoto')}
                  className="absolute top-2 right-2 w-6 h-6 rounded-full bg-red-500 text-white flex items-center justify-center"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>
            ) : (
              <label className="block">
                <input
                  type="file"
                  accept="image/*"
                  capture="environment"
                  onChange={(e) => handlePhotoCapture(e, 'carPhoto')}
                  className="hidden"
                />
                <div 
                  data-testid="car-photo-upload"
                  className="aspect-[4/3] rounded-xl border-2 border-dashed border-slate-300 bg-slate-50 flex flex-col items-center justify-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-colors"
                >
                  <Camera className="w-8 h-8 text-slate-400 mb-2" />
                  <span className="text-xs text-slate-500">Tap to capture</span>
                </div>
              </label>
            )}
          </div>

          {/* Odometer Photo */}
          <div>
            <div className="text-xs text-slate-500 font-medium mb-2">Odometer</div>
            {vehicleData.odometerPhoto ? (
              <div className="relative aspect-[4/3] rounded-xl overflow-hidden bg-slate-100">
                <img 
                  src={vehicleData.odometerPhoto} 
                  alt="Odometer" 
                  className="w-full h-full object-cover"
                />
                <button
                  onClick={() => removePhoto('odometerPhoto')}
                  className="absolute top-2 right-2 w-6 h-6 rounded-full bg-red-500 text-white flex items-center justify-center"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>
            ) : (
              <label className="block">
                <input
                  type="file"
                  accept="image/*"
                  capture="environment"
                  onChange={(e) => handlePhotoCapture(e, 'odometerPhoto')}
                  className="hidden"
                />
                <div 
                  data-testid="odometer-photo-upload"
                  className="aspect-[4/3] rounded-xl border-2 border-dashed border-slate-300 bg-slate-50 flex flex-col items-center justify-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-colors"
                >
                  <Camera className="w-8 h-8 text-slate-400 mb-2" />
                  <span className="text-xs text-slate-500">Tap to capture</span>
                </div>
              </label>
            )}
          </div>
        </div>
      </main>

      {/* Fixed Bottom Button */}
      <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-4">
        <Button
          data-testid="proceed-inspection-btn"
          onClick={handleProceed}
          className="w-full h-14 bg-blue-600 hover:bg-blue-700 text-white font-bold text-base rounded-xl flex items-center justify-center gap-2"
        >
          Proceed to Inspection
          <ChevronRight className="w-5 h-5" />
        </Button>
      </div>
    </div>
  );
}
