import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  Loader2, CheckCircle2, ChevronRight, Bluetooth, Car, Copy, 
  Wrench, Battery, Gauge, CircleDot, Settings, ClipboardCheck,
  Shield, ArrowRight
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle,
  DialogDescription 
} from '@/components/ui/dialog';
import { inspectionsApi } from '@/lib/api';
import { toast } from 'sonner';

// Icon mapping for categories
const CATEGORY_ICONS = {
  'engine': Settings,
  'transmission': Gauge,
  'battery': Battery,
  'suspension': CircleDot,
  'tires': Wrench,
  'default': ClipboardCheck
};

const CATEGORY_GRADIENTS = {
  'engine': 'from-orange-500 to-amber-500',
  'transmission': 'from-blue-500 to-cyan-500',
  'battery': 'from-emerald-500 to-green-500',
  'suspension': 'from-purple-500 to-violet-500',
  'tires': 'from-rose-500 to-red-500',
  'default': 'from-slate-500 to-slate-600'
};

// Mock Bluetooth devices
const MOCK_BLUETOOTH_DEVICES = [
  { id: 'obd1', name: 'OBDII Scanner', type: 'OBD' },
  { id: 'obd2', name: 'ELM327 v2.1', type: 'OBD' },
];

export default function InspectionChecklistPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [inspection, setInspection] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [categories, setCategories] = useState([]);
  const [categoryProgress, setCategoryProgress] = useState({});
  const [trackingId, setTrackingId] = useState('');
  const [isCompleting, setIsCompleting] = useState(false);
  const [questionnaire, setQuestionnaire] = useState(null);
  
  // OBD States
  const [showBluetoothDialog, setShowBluetoothDialog] = useState(false);
  const [bluetoothScanning, setBluetoothScanning] = useState(false);
  const [bluetoothDevices, setBluetoothDevices] = useState([]);
  const [selectedDevice, setSelectedDevice] = useState(null);
  const [obdConnecting, setObdConnecting] = useState(false);
  const [obdScanning, setObdScanning] = useState(false);
  const [obdComplete, setObdComplete] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);
      try {
        // Fetch inspection details
        const inspData = await inspectionsApi.getInspection(id);
        setInspection(inspData);
        setTrackingId(inspData.orderId || `ORD${Math.random().toString().slice(2, 12)}`);
        
        // Fetch questionnaire from CRM backend
        try {
          const questionnaireData = await inspectionsApi.getQuestionnaire(id);
          setQuestionnaire(questionnaireData);
          
          // Group questions by category
          const categoryMap = {};
          const questions = questionnaireData.questions || [];
          
          questions.forEach(q => {
            const catId = q.category_id || 'general';
            const catName = q.category_name || 'General';
            
            if (!categoryMap[catId]) {
              categoryMap[catId] = {
                id: catId,
                name: catName,
                description: `Questions for ${catName}`,
                totalItems: 0,
                questions: []
              };
            }
            categoryMap[catId].totalItems++;
            categoryMap[catId].questions.push(q);
          });
          
          const categoriesArray = Object.values(categoryMap);
          
          // If no questions from backend, use default categories
          if (categoriesArray.length === 0) {
            setCategories([
              { id: 'engine', name: 'Engine Health', description: 'Engine diagnostics & performance', totalItems: 7 },
              { id: 'transmission', name: 'Transmission', description: 'Gearbox & clutch system', totalItems: 4 },
              { id: 'battery', name: 'Battery Health', description: 'Electrical & charging system', totalItems: 3 },
              { id: 'suspension', name: 'Suspension & Brakes', description: 'Safety & handling inspection', totalItems: 4 },
              { id: 'tires', name: 'Tires & Tools', description: 'Tire condition & spare tools', totalItems: 5 }
            ]);
          } else {
            setCategories(categoriesArray);
          }
          
          // Initialize progress
          const progress = {};
          categoriesArray.forEach(cat => {
            progress[cat.id] = 0; // Start with 0, will be updated as mechanic answers
          });
          setCategoryProgress(progress);
          
        } catch (qErr) {
          console.log('Could not fetch questionnaire, using defaults:', qErr);
          // Fallback to static categories
          setCategories([
            { id: 'engine', name: 'Engine Health', description: 'Engine diagnostics & performance', totalItems: 7 },
            { id: 'transmission', name: 'Transmission', description: 'Gearbox & clutch system', totalItems: 4 },
            { id: 'battery', name: 'Battery Health', description: 'Electrical & charging system', totalItems: 3 },
            { id: 'suspension', name: 'Suspension & Brakes', description: 'Safety & handling inspection', totalItems: 4 },
            { id: 'tires', name: 'Tires & Tools', description: 'Tire condition & spare tools', totalItems: 5 }
          ]);
          
          // Initialize with full progress for demo
          setCategoryProgress({
            engine: 7,
            transmission: 4,
            battery: 3,
            suspension: 4,
            tires: 5
          });
        }
        
      } catch (err) {
        toast.error('Failed to load inspection');
        navigate('/');
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, [id, navigate]);

  const handleCategoryClick = (categoryId) => {
    // Store questionnaire data in localStorage for the category page
    if (questionnaire) {
      const categoryQuestions = questionnaire.questions?.filter(q => q.category_id === categoryId) || [];
      localStorage.setItem(`questions_${id}_${categoryId}`, JSON.stringify(categoryQuestions));
    }
    navigate(`/category/${id}/${categoryId}`);
  };

  const handleStartOBD = () => {
    setShowBluetoothDialog(true);
    setBluetoothScanning(true);
    setTimeout(() => {
      setBluetoothDevices(MOCK_BLUETOOTH_DEVICES);
      setBluetoothScanning(false);
    }, 2000);
  };

  const handleSelectDevice = async (device) => {
    setSelectedDevice(device);
    setObdConnecting(true);
    
    setTimeout(() => {
      setObdConnecting(false);
      toast.success(`Connected to ${device.name}`);
      setObdScanning(true);
      
      setTimeout(() => {
        setObdScanning(false);
        setObdComplete(true);
        setShowBluetoothDialog(false);
        toast.success('OBD Scan completed successfully');
      }, 3000);
    }, 2000);
  };

  const handleCopyTrackingId = () => {
    navigator.clipboard.writeText(trackingId);
    toast.success('Tracking ID copied');
  };

  const handleCompleteInspection = async () => {
    setIsCompleting(true);
    try {
      await inspectionsApi.completeInspection(id);
      toast.success('Inspection completed successfully!');
      navigate('/');
    } catch (err) {
      toast.error('Failed to complete inspection');
    } finally {
      setIsCompleting(false);
    }
  };

  const totalItems = categories.reduce((sum, cat) => sum + cat.totalItems, 0);
  const completedItems = categories.reduce((sum, cat) => sum + (categoryProgress[cat.id] || 0), 0);
  const overallProgress = totalItems > 0 ? Math.round((completedItems / totalItems) * 100) : 0;
  const allCategoriesComplete = categories.every(
    cat => categoryProgress[cat.id] === cat.totalItems
  );

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-b from-slate-900 via-slate-800 to-slate-900 pb-28">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-slate-900/95 backdrop-blur-sm border-b border-slate-700/50">
        <div className="flex items-center justify-between px-4 h-14">
          <button 
            onClick={() => navigate(-1)}
            className="w-10 h-10 flex items-center justify-center text-white/70 hover:text-white transition-colors"
          >
            <ChevronRight className="w-6 h-6 rotate-180" />
          </button>
          <div className="flex items-center gap-2">
            <Shield className="w-5 h-5 text-blue-400" />
            <span className="text-white font-bold tracking-wide">INSPECTION</span>
          </div>
          <div className="w-10" />
        </div>
      </header>

      {/* Progress Overview Card */}
      <div className="px-4 pt-4">
        <div className="bg-gradient-to-br from-blue-600 to-blue-700 rounded-2xl p-5 shadow-xl shadow-blue-900/30">
          <div className="flex items-center justify-between mb-4">
            <div>
              <div className="text-blue-100 text-xs font-medium uppercase tracking-wider mb-1">Overall Progress</div>
              <div className="text-white text-3xl font-bold">{overallProgress}%</div>
            </div>
            <div className="w-16 h-16 rounded-full bg-white/10 flex items-center justify-center">
              <ClipboardCheck className="w-8 h-8 text-white" />
            </div>
          </div>
          <div className="h-2 bg-white/20 rounded-full overflow-hidden">
            <div 
              className="h-full bg-white rounded-full transition-all duration-500"
              style={{ width: `${overallProgress}%` }}
            />
          </div>
          <div className="flex justify-between mt-2 text-xs text-blue-100">
            <span>{completedItems} of {totalItems} items checked</span>
            <span>{INSPECTION_CATEGORIES.length} categories</span>
          </div>
        </div>
      </div>

      {/* Tracking ID */}
      <div className="px-4 pt-4">
        <div className="bg-slate-800/50 backdrop-blur rounded-xl p-4 flex items-center justify-between border border-slate-700/50">
          <div>
            <div className="text-slate-400 text-xs font-medium uppercase tracking-wider">Tracking ID</div>
            <div className="text-white font-bold text-lg mt-0.5">{trackingId}</div>
          </div>
          <button
            data-testid="copy-tracking-btn"
            onClick={handleCopyTrackingId}
            className="w-10 h-10 rounded-xl bg-slate-700/50 flex items-center justify-center text-slate-300 hover:bg-slate-700 hover:text-white transition-colors"
          >
            <Copy className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Categories */}
      <div className="px-4 pt-5">
        <h2 className="text-slate-400 text-xs font-semibold uppercase tracking-wider mb-3 px-1">
          Inspection Categories
        </h2>
        <div className="space-y-3">
          {categories.map((category) => {
            const completed = categoryProgress[category.id] || 0;
            const isComplete = completed === category.totalItems;
            const progressPercent = category.totalItems > 0 ? (completed / category.totalItems) * 100 : 0;
            const Icon = CATEGORY_ICONS[category.id] || CATEGORY_ICONS.default;
            const gradient = CATEGORY_GRADIENTS[category.id] || CATEGORY_GRADIENTS.default;
            
            return (
              <button
                key={category.id}
                data-testid={`category-${category.id}`}
                onClick={() => handleCategoryClick(category.id)}
                className="w-full bg-slate-800/60 backdrop-blur rounded-2xl p-4 flex items-center gap-4 border border-slate-700/50 hover:border-slate-600/50 hover:bg-slate-800/80 transition-all active:scale-[0.99]"
              >
                {/* Icon */}
                <div className={`w-12 h-12 rounded-xl bg-gradient-to-br ${gradient} flex items-center justify-center flex-shrink-0 shadow-lg`}>
                  <Icon className="w-6 h-6 text-white" />
                </div>
                
                {/* Content */}
                <div className="flex-1 text-left">
                  <div className="flex items-center justify-between mb-1">
                    <span className="font-semibold text-white text-sm">{category.name}</span>
                    <span className={`text-xs font-bold ${isComplete ? 'text-emerald-400' : 'text-slate-400'}`}>
                      {completed}/{category.totalItems}
                    </span>
                  </div>
                  <div className="text-slate-400 text-xs mb-2">{category.description}</div>
                  <div className="h-1.5 bg-slate-700 rounded-full overflow-hidden">
                    <div 
                      className={`h-full rounded-full transition-all ${isComplete ? 'bg-emerald-500' : 'bg-blue-500'}`}
                      style={{ width: `${progressPercent}%` }}
                    />
                  </div>
                </div>

                {/* Status */}
                {isComplete ? (
                  <CheckCircle2 className="w-6 h-6 text-emerald-400 flex-shrink-0" />
                ) : (
                  <ArrowRight className="w-5 h-5 text-slate-500 flex-shrink-0" />
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* OBD Scan Section */}
      <div className="px-4 pt-5">
        <h2 className="text-slate-400 text-xs font-semibold uppercase tracking-wider mb-3 px-1">
          Diagnostic Scan
        </h2>
        <div className="bg-slate-800/60 backdrop-blur rounded-2xl p-4 border border-slate-700/50">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-gradient-to-br from-slate-600 to-slate-700 rounded-xl flex items-center justify-center shadow-lg">
                <Car className="w-6 h-6 text-white" />
              </div>
              <div>
                <div className="font-semibold text-white text-sm">OBD Scanner</div>
                <div className="text-xs text-slate-400 mt-0.5">
                  {obdComplete ? 'Scan completed • No errors found' : 'Connect to read vehicle data'}
                </div>
              </div>
            </div>
            
            {obdComplete ? (
              <div className="flex items-center gap-2 text-emerald-400">
                <CheckCircle2 className="w-5 h-5" />
              </div>
            ) : (
              <Button
                data-testid="start-obd-btn"
                onClick={handleStartOBD}
                size="sm"
                className="bg-blue-600 hover:bg-blue-500 text-white font-semibold rounded-xl px-4 h-9"
              >
                Scan
              </Button>
            )}
          </div>
        </div>
      </div>

      {/* Fixed Bottom Button */}
      <div className="fixed bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-slate-900 via-slate-900 to-transparent pt-8">
        <Button
          data-testid="complete-inspection-btn"
          onClick={handleCompleteInspection}
          disabled={!allCategoriesComplete || isCompleting}
          className="w-full h-14 bg-gradient-to-r from-emerald-500 to-emerald-600 hover:from-emerald-400 hover:to-emerald-500 disabled:from-slate-700 disabled:to-slate-700 disabled:text-slate-500 text-white font-bold text-base rounded-xl shadow-lg shadow-emerald-900/30 transition-all"
        >
          {isCompleting ? (
            <Loader2 className="w-5 h-5 animate-spin" />
          ) : (
            <>
              <CheckCircle2 className="w-5 h-5 mr-2" />
              Complete Inspection
            </>
          )}
        </Button>
      </div>

      {/* Bluetooth Dialog */}
      <Dialog open={showBluetoothDialog} onOpenChange={setShowBluetoothDialog}>
        <DialogContent className="max-w-sm mx-4 rounded-2xl bg-slate-800 border-slate-700">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 text-white">
              <Bluetooth className="w-5 h-5 text-blue-400" />
              {obdConnecting ? 'Connecting...' : obdScanning ? 'Scanning Vehicle...' : 'Select OBD Device'}
            </DialogTitle>
            <DialogDescription className="text-slate-400">
              {bluetoothScanning 
                ? 'Scanning for nearby Bluetooth devices...'
                : obdConnecting
                ? `Connecting to ${selectedDevice?.name}...`
                : obdScanning
                ? 'Reading vehicle diagnostic data...'
                : 'Select your OBD scanner from the list'
              }
            </DialogDescription>
          </DialogHeader>

          <div className="py-4">
            {bluetoothScanning || obdConnecting || obdScanning ? (
              <div className="flex flex-col items-center py-8">
                <Loader2 className="w-10 h-10 animate-spin text-blue-400 mb-4" />
                <div className="text-sm text-slate-400">
                  {obdScanning ? 'Please wait...' : 'Searching...'}
                </div>
              </div>
            ) : (
              <div className="space-y-2">
                {bluetoothDevices.map((device) => (
                  <button
                    key={device.id}
                    data-testid={`bluetooth-device-${device.id}`}
                    onClick={() => handleSelectDevice(device)}
                    className="w-full flex items-center justify-between p-4 rounded-xl border border-slate-600 hover:border-blue-500/50 hover:bg-slate-700/50 transition-colors"
                  >
                    <div className="flex items-center gap-3">
                      <Car className="w-5 h-5 text-blue-400" />
                      <span className="font-medium text-white">{device.name}</span>
                    </div>
                    <ChevronRight className="w-5 h-5 text-slate-500" />
                  </button>
                ))}
              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}
