import React from 'react';
import { ChevronLeft, Menu, Calendar, Filter } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar as CalendarComponent } from '@/components/ui/calendar';
import { useNavigate } from 'react-router-dom';

const DEFAULT_LOGO = "https://customer-assets.emergentagent.com/job_mechanic-assist-10/artifacts/wxp3v8bu_Wisedrive%20New%20Logo%20Horizontal%20Black%20Trans%20BG.png";

export const Header = ({ 
  title, 
  showBack = false, 
  showMenu = true,
  onMenuClick,
  rightContent,
  logo = DEFAULT_LOGO,
  showFilters = false,
  selectedDate,
  onDateChange,
  onFilterClick,
  hasActiveFilters = false
}) => {
  const navigate = useNavigate();

  return (
    <header 
      data-testid="app-header"
      className="fixed top-0 left-0 right-0 h-16 bg-white border-b border-slate-100 flex items-center justify-between px-2 z-50"
    >
      {/* Left Side */}
      <div className="w-12 h-12 flex items-center justify-center">
        {showBack ? (
          <Button
            data-testid="header-back-btn"
            variant="ghost"
            size="icon"
            onClick={() => navigate(-1)}
            className="h-10 w-10 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full"
          >
            <ChevronLeft className="h-6 w-6" />
          </Button>
        ) : showMenu ? (
          <Button
            data-testid="header-menu-btn"
            variant="ghost"
            size="icon"
            onClick={onMenuClick}
            className="h-10 w-10 text-slate-600 hover:text-slate-900 hover:bg-slate-100 rounded-full"
          >
            <Menu className="h-6 w-6" />
          </Button>
        ) : (
          <div className="w-10" />
        )}
      </div>

      {/* Center - Logo or Title */}
      <div className="flex-1 flex items-center justify-center">
        {title ? (
          <span 
            data-testid="header-title"
            className="text-lg font-bold text-slate-900"
            style={{ fontFamily: 'Barlow Condensed, sans-serif' }}
          >
            {title}
          </span>
        ) : (
          <img 
            src={logo}
            alt="Wisedrive"
            className="h-7 object-contain"
          />
        )}
      </div>

      {/* Right Side */}
      <div className="flex items-center">
        {showFilters ? (
          <div className="flex items-center gap-0">
            <Popover>
              <PopoverTrigger asChild>
                <Button
                  data-testid="date-picker-btn"
                  variant="ghost"
                  size="icon"
                  className="h-10 w-10 text-slate-500 hover:text-slate-700"
                >
                  <Calendar className="h-5 w-5" />
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0" align="end">
                <CalendarComponent
                  mode="single"
                  selected={selectedDate ? new Date(selectedDate) : undefined}
                  onSelect={(date) => onDateChange?.(date || new Date())}
                  initialFocus
                />
              </PopoverContent>
            </Popover>

            <Button
              data-testid="filter-btn"
              variant="ghost"
              size="icon"
              onClick={onFilterClick}
              className={`h-10 w-10 relative ${hasActiveFilters ? 'text-blue-600' : 'text-slate-500'}`}
            >
              <Filter className="h-5 w-5" />
              {hasActiveFilters && (
                <span className="absolute top-1 right-1 w-2 h-2 bg-blue-600 rounded-full" />
              )}
            </Button>
          </div>
        ) : (
          rightContent || <div className="w-10" />
        )}
      </div>
    </header>
  );
};
