import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Phone, MapPin, Navigation, Check, X } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { StatusBadge } from './StatusBadge';
import { formatDate, formatTime } from '@/lib/utils';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter
} from '@/components/ui/dialog';

const REJECTION_REASONS = [
  'Not available at the scheduled time',
  'Location too far',
  'Vehicle type not supported',
  'Already have another inspection',
  'Other'
];

export const InspectionCard = ({ inspection, onAccept, onReject }) => {
  const navigate = useNavigate();
  const [showRejectDialog, setShowRejectDialog] = useState(false);
  const [selectedReason, setSelectedReason] = useState('');
  const [customReason, setCustomReason] = useState('');
  
  const { 
    id,
    scheduledAt, 
    status, 
    vehicleNumber, 
    makeModelVariant, 
    city, 
    customerName, 
    customerPhone,
    customerAddress,
    rejectionReason
  } = inspection;

  const handleCall = (e) => {
    e.stopPropagation();
    window.location.href = `tel:${customerPhone}`;
  };

  const handleNavigate = (e) => {
    e.stopPropagation();
    const query = encodeURIComponent(customerAddress || city);
    window.open(`https://www.google.com/maps/dir/?api=1&destination=${query}`, '_blank');
  };

  const handleCardClick = () => {
    if (status === 'ACCEPTED') {
      navigate(`/start-inspection/${id}`);
    }
  };

  const handleAccept = (e) => {
    e.stopPropagation();
    onAccept?.(id);
  };

  const handleRejectClick = (e) => {
    e.stopPropagation();
    setShowRejectDialog(true);
  };

  const handleConfirmReject = () => {
    const reason = selectedReason === 'Other' ? customReason : selectedReason;
    onReject?.(id, reason);
    setShowRejectDialog(false);
    setSelectedReason('');
    setCustomReason('');
  };

  const handleStartInspection = (e) => {
    e.stopPropagation();
    navigate(`/start-inspection/${id}`);
  };

  const showCustomerInfo = status === 'ACCEPTED' || status === 'COMPLETED';

  return (
    <>
      <div
        data-testid={`inspection-card-${id}`}
        onClick={handleCardClick}
        className={`bg-white rounded-2xl p-4 shadow-sm border border-slate-100 transition-all ${
          status === 'ACCEPTED' ? 'active:scale-[0.99] cursor-pointer' : ''
        }`}
      >
      {/* Top Row: Vehicle + Status */}
      <div className="flex items-start justify-between gap-3 mb-2">
        <div className="flex-1 min-w-0">
          <div 
            data-testid="vehicle-number"
            className="text-lg font-bold text-slate-900 tracking-wide truncate"
          >
            {vehicleNumber}
          </div>
          <div data-testid="car-model" className="text-sm text-slate-500 truncate">
            {makeModelVariant}
          </div>
        </div>
        <StatusBadge status={status} />
      </div>

      {/* Location + Time Row */}
      <div className="flex items-center gap-3 text-sm text-slate-500 mb-3">
        <div className="flex items-center gap-1.5">
          <MapPin className="w-3.5 h-3.5 text-slate-400" />
          <span data-testid="inspection-city">{city}</span>
        </div>
        <span className="text-slate-300">•</span>
        <span data-testid="inspection-datetime">
          {formatDate(scheduledAt)} {formatTime(scheduledAt)}
        </span>
      </div>

      {/* Customer Info - Only shown after accepting */}
      {showCustomerInfo && (
        <div className="flex items-center justify-between py-2 border-t border-slate-100">
          <span data-testid="customer-name" className="font-medium text-slate-800 text-sm">
            {customerName}
          </span>
          {status === 'ACCEPTED' && (
            <button
              data-testid="customer-call-btn"
              onClick={handleCall}
              className="flex items-center justify-center w-10 h-10 rounded-full bg-emerald-50 text-emerald-600 active:bg-emerald-100 transition-colors"
              aria-label="Call customer"
            >
              <Phone className="w-5 h-5" />
            </button>
          )}
        </div>
      )}

        {/* Action Row */}
        <div className="flex gap-2 mt-3">
          {status === 'NEW' && (
            <>
              <Button
                data-testid="reject-btn"
                onClick={handleRejectClick}
                variant="ghost"
                className="h-10 px-3 text-red-500 hover:text-red-600 hover:bg-red-50 rounded-xl font-medium text-sm"
              >
                <X className="w-4 h-4 mr-1" />
                Reject
              </Button>
              <Button
                data-testid="accept-btn"
                onClick={handleAccept}
                className="flex-1 h-12 gap-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl font-bold text-base"
              >
                <Check className="w-5 h-5" />
                Accept
              </Button>
            </>
          )}

          {status === 'ACCEPTED' && (
            <>
              <Button
                data-testid="start-inspection-btn"
                onClick={handleStartInspection}
                className="flex-1 h-11 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-xl"
              >
                Start Inspection
              </Button>
              <Button
                data-testid="navigate-btn"
                onClick={handleNavigate}
                variant="outline"
                className="h-11 w-11 p-0 border-slate-200 rounded-xl flex items-center justify-center"
                aria-label="Navigate to location"
              >
                <Navigation className="w-5 h-5 text-blue-600" />
              </Button>
            </>
          )}

          {status === 'COMPLETED' && (
            <div className="w-full flex items-center justify-center gap-2 py-2 text-emerald-600">
              <Check className="w-5 h-5" />
              <span className="font-medium text-sm">Inspection Completed</span>
            </div>
          )}

          {status === 'REJECTED' && (
            <div className="w-full py-2">
              <div className="text-center text-sm text-slate-400">You rejected this inspection</div>
              {rejectionReason && (
                <div className="text-center text-xs text-slate-400 mt-1">
                  Reason: {rejectionReason}
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Rejection Reason Dialog */}
      <Dialog open={showRejectDialog} onOpenChange={setShowRejectDialog}>
        <DialogContent 
          className="w-[calc(100%-32px)] max-w-sm rounded-2xl p-5" 
          onClick={(e) => e.stopPropagation()}
        >
          <DialogHeader className="text-left">
            <DialogTitle className="text-lg font-bold text-slate-900">Reject Inspection</DialogTitle>
            <DialogDescription className="text-sm text-slate-500 mt-1">
              Please select a reason for rejecting this inspection
            </DialogDescription>
          </DialogHeader>
          
          <div className="py-3 space-y-2 max-h-[50vh] overflow-y-auto">
            {REJECTION_REASONS.map((reason) => (
              <button
                key={reason}
                data-testid={`reject-reason-${reason.toLowerCase().replace(/\s+/g, '-')}`}
                onClick={() => setSelectedReason(reason)}
                className={`w-full text-left p-3.5 rounded-xl border-2 transition-all ${
                  selectedReason === reason
                    ? 'border-red-500 bg-red-50 text-red-700'
                    : 'border-slate-200 hover:border-slate-300 text-slate-700'
                }`}
              >
                <span className="text-sm font-medium">{reason}</span>
              </button>
            ))}
            
            {selectedReason === 'Other' && (
              <textarea
                data-testid="custom-reject-reason"
                value={customReason}
                onChange={(e) => setCustomReason(e.target.value)}
                placeholder="Please specify your reason..."
                className="w-full p-3.5 rounded-xl border-2 border-slate-200 text-sm resize-none h-24 focus:outline-none focus:border-red-500 mt-2"
              />
            )}
          </div>

          <DialogFooter className="flex flex-row gap-3 mt-2">
            <Button
              variant="outline"
              onClick={() => setShowRejectDialog(false)}
              className="flex-1 h-12 rounded-xl font-semibold border-2"
            >
              Cancel
            </Button>
            <Button
              data-testid="confirm-reject-btn"
              onClick={handleConfirmReject}
              disabled={!selectedReason || (selectedReason === 'Other' && !customReason.trim())}
              className="flex-1 h-12 bg-red-600 hover:bg-red-700 text-white rounded-xl font-semibold"
            >
              Reject
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
};
